INSERT INTO public.neuron_templates (name, description, category, blocks_template, is_public, usage_count, default_tags) VALUES ('Cliffhanger: Rețeta Completă', 'Ghid complet: 7 principii + 8 tipuri de cliffhanger + exerciții practice pentru construirea suspansului.', 'Codul Cușnir', '[{"type":"heading","content":"Rețeta unui Cliffhanger Perfect"},{"type":"text","content":"Cliffhangerele transformă sesiuni obișnuite în experiențe captivante care provoacă curiozitate."},{"type":"subheading","content":"7 Principii Fundamentale"},{"type":"idea","content":"1. Promite o revelație viitoare — identifică problema, fă promisiunea intrigantă"},{"type":"idea","content":"2. Stârnește curiozitatea — paradoxuri, întrebări retorice, teasing"},{"type":"idea","content":"3. Creează o întrebare nerezolvată — lasă un element de mister"},{"type":"idea","content":"4. Folosește limbajul potrivit — verbe de acțiune, termeni emoționali"},{"type":"idea","content":"5. Evocă o schimbare semnificativă — nu un sfat oarecare, ci o tehnică revoluționară"},{"type":"idea","content":"6. Construiește încrederea — dovezi, povești, studii de caz"},{"type":"idea","content":"7. Evită prea multe detalii — secretul vine din absența completă"},{"type":"divider","content":""},{"type":"subheading","content":"8 Tipuri de Cliffhanger"},{"type":"list","content":"1. De Revelație — dezvăluirea unui secret. 2. Emoțional — stare emoțională intensă. 3. De Acțiune — oprește narațiunea. 4. De Mister — element enigmatic. 5. De Transformare — schimbare majoră. 6. De Dilemă — alegere. 7. De Conflict — nerezolvat. 8. De Promisiune — ceva valoros în viitor."},{"type":"divider","content":""},{"type":"subheading","content":"Exercițiu Practic"},{"type":"todo","content":"Identifică un punct de durere al audienței"},{"type":"todo","content":"Creează o promisiune fără a dezvălui soluția"},{"type":"todo","content":"Alege tipul de cliffhanger potrivit"},{"type":"todo","content":"Testează pe 3 audiențe diferite"}]'::jsonb, true, 0, ARRAY['cliffhanger','suspans','engagement']);